const allItems = [];

for (const item of $input.all()) {
  // 1. Obtener datos de configuración originales
  const from_currency = item.json.from_currency;
  const to_currency = item.json.to_currency;
  const rate_type = item.json.rate_type;

  // Leemos la bandera 'inverse' para pasarla al resultado
  const is_inverse = item.json.inverse === true; 

  // 2. Determinar la fuente y extraer observaciones
  let observations = [];
  let provider_id = '';

  // Estructura de Banxico
  if (item.json.bmx && item.json.bmx.series && item.json.bmx.series[0]) {
    observations = item.json.bmx.series[0].datos || [];
    provider_id = 'banxico';
  }
  // Estructura de FRED
  else if (item.json.observations) {
    observations = item.json.observations;
    provider_id = 'fred';
  }

  // 3. Procesar las observaciones
  for (const obs of observations) {
    let raw_rate = 0;
    let rate_date = '';

    // --- LÓGICA BANXICO ---
    if (provider_id === 'banxico') {
      if (!obs.dato || obs.dato === 'N/E') continue;

      // Limpiar comas y parsear
      raw_rate = parseFloat(obs.dato.replace(/,/g, ''));
      rate_date = obs.fecha; 

      // Normalizar Fecha (DD/MM/YYYY -> YYYY-MM-DD)
      if (rate_date.includes('/')) {
        const [d, m, y] = rate_date.split('/');
        rate_date = `${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`;
      }
    } 

    // --- LÓGICA FRED ---
    else if (provider_id === 'fred') {
      if (!obs.value || obs.value === '.') continue;

      raw_rate = parseFloat(obs.value);
      rate_date = obs.date; 
    }

    // 4. Validar número
    if (isNaN(raw_rate) || raw_rate <= 0) continue;

    // 5. GUARDAR RESULTADO (SIN INVERTIR)
    // Se guarda el dato crudo y las etiquetas originales.
    allItems.push({
      json: {
        from_currency: from_currency,
        to_currency: to_currency,
        rate_type: rate_type,
        provider_id: provider_id,
        rate_date: rate_date,

        rate: raw_rate,          // Valor original (ej. 150.00 para JPY)
        is_inverse: is_inverse   // Bandera para saber que este dato es "inverso"
      }
    });
  }
}

console.log(`Total items procesados: ${allItems.length}`);

return allItems;

// 1. Configuración FRED
const FRED_API_KEY = 'e28c7bf00d9418ff0e3668963ea8a915'; 
const HISTORIC_START = '1990-01-01'; // Fecha por defecto si la moneda es nueva

// 2. Definimos las monedas que QUEREMOS buscar (Tu Mapa Maestro)
const FRED_TARGETS = [
  // Pares Inversos (Moneda -> USD)
  { id: 'DEXJPUS', from: 'USD', to: 'JPY', type: 'SPOT', inverse: true },
  { id: 'DEXSZUS', from: 'USD', to: 'CHF', type: 'SPOT', inverse: true },
  { id: 'DEXCAUS', from: 'USD', to: 'CAD', type: 'SPOT', inverse: true },
  { id: 'DEXCHUS', from: 'USD', to: 'CNY', type: 'SPOT', inverse: true },
  { id: 'DEXBZUS', from: 'USD', to: 'BRL', type: 'SPOT', inverse: true },
  { id: 'DEXKOUS', from: 'USD', to: 'KRW', type: 'SPOT', inverse: true },

  // Pares Directos (Euro, Libra, Australia)
  { id: 'DEXUSEU', from: 'EUR', to: 'USD', type: 'SPOT', inverse: false },
  { id: 'DEXUSUK', from: 'GBP', to: 'USD', type: 'SPOT', inverse: false },
  { id: 'DEXUSAL', from: 'AUD', to: 'USD', type: 'SPOT', inverse: false },

  // MXN en Fred (Opcional, si lo quieres comparar con Banxico)
  { id: 'DEXMXUS', from: 'USD', to: 'MXN', type: 'SPOT', inverse: true }
];

// 3. Fechas
const today = DateTime.now().setZone('America/Mexico_City');
const endDateStr = today.toFormat('yyyy-MM-dd');

// 4. CREAR DICCIONARIO DE LA BD
// Convertimos el input de SQL en un objeto rápido de buscar
// Clave: "USD_JPY_SPOT", Valor: "2026-02-13"
const dbIndex = {};
for (const item of $input.all()) {
    const key = `${item.json.from_currency}_${item.json.to_currency}_${item.json.rate_type}`;
    dbIndex[key] = item.json.last_db_date;
}

const results = [];

// 5. BUCLE PRINCIPAL (Iteramos sobre el MAPA, no sobre el Input)
for (const target of FRED_TARGETS) {

    // Generamos la clave de búsqueda
    const key = `${target.from}_${target.to}_${target.type}`;
    const last_db_date = dbIndex[key];

    // Calculamos Start Date
    let startDateStr = HISTORIC_START;

    if (last_db_date) {
        // Si existe en BD, calculamos día siguiente
        const lastDateObj = DateTime.fromISO(last_db_date);
        if (lastDateObj.isValid) {
            startDateStr = lastDateObj.plus({ days: 1 }).toFormat('yyyy-MM-dd');
        }
    } else {
        console.log(`🆕 Moneda nueva detectada: ${target.id}. Descargando historial completo.`);
    }

    // Validación de "Ya estamos al día"
    if (startDateStr > endDateStr) {
        // console.log(`✅ ${target.id} al día.`);
        continue;
    }

    // Agregar a la lista de descargas
    results.push({
        json: {
            series_id: target.id,
            start_date: startDateStr,
            end_date: endDateStr,
            api_key: FRED_API_KEY,
            from_currency: target.from,
            to_currency: target.to,
            rate_type: target.type,
            inverse: target.inverse,
            provider: 'fred'
        }
    });
}

console.log(`Total FRED a descargar: ${results.length}`);
return results;

// 1. Configuración General
const API_KEY = '72a341c34753f332e7d4e13864a3affa9693e4199687156ed8b544ba7677acfd'; 

// 2. EL MAPA MAESTRO (Indispensable para recuperar los IDs que faltan en el SQL)
const SERIES_MAP = [
  // --- BANXICO ---
  { id: 'SF43718',  from: 'USD', to: 'MXN', type: 'FIX' },
  { id: 'SF60653',  from: 'USD', to: 'MXN', type: 'SPOT' },
  { id: 'SF343410', from: 'USD', to: 'MXN', type: 'CLOSE' },
  { id: 'SF46410',  from: 'EUR', to: 'MXN', type: 'FIX' },
  { id: 'SF46406',  from: 'JPY', to: 'MXN', type: 'FIX' },
  { id: 'SF46407',  from: 'GBP', to: 'MXN', type: 'FIX' },
  { id: 'SF60632',  from: 'CAD', to: 'MXN', type: 'FIX' },
  { id: 'SP68257',  from: 'UDI', to: 'MXN', type: 'INFLATION' }, // Ojo: En tu imagen dice "INFLATION"
  { id: 'SF290383', from: 'CNY', to: 'MXN', type: 'FIX' },

  // --- FRED (Por si acaso vienen en el SQL) ---
  { id: 'DEXUSEU', from: 'EUR', to: 'USD', type: 'SPOT' },
  { id: 'DEXJPUS', from: 'USD', to: 'JPY', type: 'SPOT' },
  { id: 'DEXSZUS', from: 'USD', to: 'CHF', type: 'SPOT' },
  { id: 'DEXCAUS', from: 'USD', to: 'CAD', type: 'SPOT' },
  { id: 'DEXUSUK', from: 'GBP', to: 'USD', type: 'SPOT' },
  { id: 'DEXUSAL', from: 'AUD', to: 'USD', type: 'SPOT' },
  { id: 'DEXCHUS', from: 'USD', to: 'CNY', type: 'SPOT' },
  { id: 'DEXBZUS', from: 'USD', to: 'BRL', type: 'SPOT' },
  { id: 'DEXKOUS', from: 'USD', to: 'KRW', type: 'SPOT' }
];

// 3. Definimos "HOY"
const today = DateTime.now().setZone('America/Mexico_City');
const endDateStr = today.toFormat('yyyy-MM-dd');

console.log(`--- INICIO --- Fecha objetivo: ${endDateStr}`);

const results = [];

// 4. Procesamos la entrada (Input del SQL)
for (const item of $input.all()) {

  // Extraemos datos tal cual vienen de tu imagen de SQL
  const db_from = item.json.from_currency;
  const db_to   = item.json.to_currency;
  const db_type = item.json.rate_type;
  let last_db_date = item.json.last_db_date;

  // --- PASO CRÍTICO: RECUPERAR EL ID ---
  // Buscamos en el mapa qué serie coincide
  const configMatch = SERIES_MAP.find(s => 
      s.from === db_from && 
      s.to === db_to && 
      s.type === db_type
  );

  if (!configMatch) {
      // Si no está en el mapa, lo saltamos y avisamos
      console.log(`⚠️ ID Desconocido para: ${db_from}/${db_to} tipo ${db_type}`);
      continue;
  }

  const series_id = configMatch.id;

  // --- REGLA DE ORO: SI NO HAY FECHA, NO HACEMOS NADA ---
  if (!last_db_date) {
      console.log(`🛑 OMITIDO: ${series_id} no tiene fecha en BD. Se ignora carga histórica.`);
      continue; 
  }

  // --- CÁLCULO DE FECHAS ---
  let startDateStr = '';
  let lastDateObj;

  // Manejo robusto de fechas (String vs Date Object)
  if (typeof last_db_date === 'object') {
      lastDateObj = DateTime.fromJSDate(last_db_date);
  } else {
      lastDateObj = DateTime.fromISO(last_db_date); 
      if (!lastDateObj.isValid) lastDateObj = DateTime.fromSQL(last_db_date);
  }

  if (lastDateObj.isValid) {
      // Pedimos desde el día siguiente
      startDateStr = lastDateObj.plus({ days: 1 }).toFormat('yyyy-MM-dd');
  } else {
      console.log(`⚠️ Fecha inválida en BD: ${last_db_date}`);
      continue;
  }

  // Validación: Si la fecha de inicio es mayor o igual a hoy, ya estamos al día
  // (Nota: > endDateStr evita pedir datos futuros, >= evita pedir el día de hoy si ya pasó el corte, ajusta según necesidad)
  if (startDateStr > endDateStr) {
    console.log(`✅ AL DÍA: ${series_id}. (BD: ${last_db_date})`);
    continue; 
  }

  // --- DETECTAR PROVEEDOR ---
  let provider = 'banxico'; // Por defecto
  if (series_id.startsWith('DEX')) provider = 'fred';

  // --- DETERMINAR INVERSE ---
  // Banxico siempre false. FRED depende de la moneda (lo simplificamos aquí o usamos configMatch si agregas el campo inverse al mapa)
  // Para simplificar, pasamos lo básico y dejamos que el procesador final maneje detalles si es necesario,
  // pero lo ideal es agregarlo al MAPA arriba.
  let is_inverse = false;
  if (provider === 'fred') {
      // Lista rápida de inversos comunes en FRED
      if (['JPY', 'CHF', 'CAD', 'CNY', 'BRL', 'KRW', 'MXN'].includes(db_to)) is_inverse = true;
  }

  console.log(`🔄 ACTUALIZANDO: ${series_id} (${startDateStr} -> ${endDateStr})`);

  results.push({
    json: {
      series_id: series_id,
      start_date: startDateStr,
      end_date: endDateStr,

      api_key: API_KEY,
      from_currency: db_from,
      to_currency: db_to,
      rate_type: db_type,
      inverse: is_inverse,
      provider: provider
    }
  });
}

console.log(`Total a descargar: ${results.length}`);
return results;
